88	// NewPreDispatchLintHook constructs the bead-lifecycle lint hook used before
89	// execute-loop dispatch.
90	func NewPreDispatchLintHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (LintResult, error) {
91		return func(ctx context.Context, beadID string) (LintResult, error) {
92			if ctx != nil {
93				if err := ctx.Err(); err != nil {
94					return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
95				}
96			}
97			if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
98				return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingSkill, Err: err}
99			}
100			if store == nil {
101				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("bead reader required")}
102			}
103	
104			b, err := store.Get(beadID)
105			if err != nil {
106				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("load bead %s: %w", beadID, err)}
107			}
108	
109			if findings := escalation.LintExecutionHints(b); len(findings) > 0 {
110				rationaleParts := make([]string, 0, len(findings))
111				suggestedFixes := make([]string, 0, len(findings))
112				for _, finding := range findings {
113					rationaleParts = append(rationaleParts, finding.Message)
114					suggestedFixes = append(suggestedFixes, finding.Message)
115				}
116				return LintResult{
117					Score:          0,
118					Rationale:      strings.Join(rationaleParts, "; "),
119					SuggestedFixes: suggestedFixes,
120				}, nil
121			}
122	
123			prompt, err := buildPreDispatchLintPrompt(b)
124			if err != nil {
125				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
126			}
127	
128			result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
129				Prompt:       prompt,
130				WorkDir:      projectRoot,
131				PromptSource: "bead-lifecycle-lint",
132			})
133			if err != nil {
134				switch {
135				case errors.Is(err, context.Canceled), errors.Is(err, context.DeadlineExceeded):
136					return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
137				case isUnknownHarnessError(err):
138					return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingHarness, Err: err}
139				case isMissingSkillError(err):
140					return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingSkill, Err: err}
141				default:
142					return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
143				}
144			}
145	
146			payload, parseErr := lintResultPayload(result)
147			if parseErr != nil {
148				return LintResult{}, parseErr
149			}
150			var out LintResult
151			if err := json.Unmarshal([]byte(payload), &out); err != nil {
152				return LintResult{}, &LintHookError{Kind: LintHookErrorKindBadJSON, Err: err}
153			}
154			return out, nil
155		}
156	}
157	
158	func buildPreDispatchLintPrompt(b *bead.Bead) (string, error) {
159		env := lintPromptBead{
160			ID:          b.ID,
161			Title:       strings.TrimSpace(b.Title),
162			Type:        b.IssueType,
163			Labels:      append([]string(nil), b.Labels...),
164			Parent:      strings.TrimSpace(b.Parent),
165			Deps:        append([]string(nil), b.DepIDs()...),
166			Description: strings.TrimSpace(b.Description),
167			Acceptance:  strings.TrimSpace(b.Acceptance),
168			Notes:       strings.TrimSpace(b.Notes),
169		}
170		if len(b.Extra) > 0 {
171			env.Custom = lintPromptCustomFields(b.Extra)
172		}
173	
174		body, err := json.MarshalIndent(env, "", "  ")
175		if err != nil {
176			return "", err
177		}
178	
179		var sb strings.Builder
180		sb.WriteString("MODE: lint\n")
181		sb.WriteString("You are the bead-lifecycle skill. Score the bead below using lint mode and return exactly one JSON object matching LintResult.\n")
182		sb.WriteString("Return only JSON with these top-level fields.\n")
183		sb.WriteString("Required output shape example: {\"score\":0,\"rationale\":\"\",\"suggested_fixes\":[],\"waivers_applied\":[]}\n")
184		sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
185		sb.WriteString("```json\n")
186		sb.Write(body)
187		sb.WriteString("\n```\n")
188		return sb.String(), nil
189	}
190	
191	func lintResultPayload(result *Result) (string, error) {
192		if result == nil {
193			return "", &LintHookError{Kind: LintHookErrorKindEmptyOutput, Err: fmt.Errorf("nil result")}
194		}
195		text := strings.TrimSpace(result.CondensedOutput)
196		if text == "" {
197			text = strings.TrimSpace(result.Output)
198		}
199		if text == "" {
200			if strings.TrimSpace(result.Error) != "" {
201				return "", &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: errors.New(strings.TrimSpace(result.Error))}
202			}
203			if result.ExitCode != 0 {
204				return "", &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("exit code %d with empty output", result.ExitCode)}
205			}
206			return "", ErrLintHookEmptyOutput
207		}
208		candidate, ok := extractJSONCandidate(text)
209		if !ok {
210			return "", &LintHookError{Kind: LintHookErrorKindBadJSON, Err: fmt.Errorf("no JSON object found")}
211		}
212		return candidate, nil
213	}
214	
215	func lintPromptCustomFields(extra map[string]any) map[string]any {
216		if len(extra) == 0 {
217			return nil
218		}
219		out := make(map[string]any, len(extra))
220		for k, v := range extra {
221			key := strings.TrimSpace(k)
222			if key == "" || lintPromptSkipCustomField(key) {
223				continue
224			}
225			if val, ok := lintPromptSafeCustomValue(v); ok {
226				out[key] = val
227			}
228		}
229		if len(out) == 0 {
230			return nil
231		}
232		return out
233	}
234	
235	func lintPromptSkipCustomField(key string) bool {
236		switch key {
237		case "events", "events_attachment", "session_id", "closing_commit_sha":
238			return true
239		}
240		for _, prefix := range []string{"claimed-", "execute-loop-", "cancel-"} {
241			if strings.HasPrefix(key, prefix) {
242				return true
243			}
244		}
245		return false
246	}
247	
248	func lintPromptSafeCustomValue(v any) (any, bool) {
249		switch val := v.(type) {
250		case nil:
251			return nil, true
252		case string:
253			if len(val) > 4096 {
254				return nil, false
255			}
256			return val, true
257		case bool, int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64:
258			return val, true
259		case []string:
260			if len(val) > 32 {
261				return nil, false
262			}
263			cp := make([]string, 0, len(val))
264			for _, item := range val {
265				if len(item) > 512 {
266					return nil, false
267				}
268				cp = append(cp, item)
269			}
270			return cp, true
271		case []any:
272			if len(val) > 32 {
273				return nil, false
274			}
275			cp := make([]string, 0, len(val))
276			for _, item := range val {
277				s, ok := item.(string)
278				if !ok || len(s) > 512 {
279					return nil, false
280				}
281				cp = append(cp, s)
282			}
283			return cp, true
284		default:
285			return nil, false
286		}
287	}
288	
289	func hasBeadLifecycleSkill(projectRoot string) bool {
290		if strings.TrimSpace(projectRoot) == "" {
291			return false
292		}
293		candidates := []string{
294			filepath.Join(projectRoot, ".agents", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
295			filepath.Join(projectRoot, ".claude", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
296		}
297		for _, p := range candidates {
298			if _, err := os.Stat(p); err == nil {
299				return true
300			}
301		}
302		return false
303	}
304	
305	func ensureBeadLifecycleSkill(projectRoot string) error {
306		if hasBeadLifecycleSkill(projectRoot) {
307			return nil
308		}
309		if err := skills.Install(skills.SkillFiles, projectRoot, skills.Options{Force: true}); err != nil {
310			return fmt.Errorf("skill missing: bead-lifecycle; auto-install failed: %w; run `ddx update --force` from the project root", err)
311		}
312		if hasBeadLifecycleSkill(projectRoot) {
313			return nil
314		}
315		return fmt.Errorf("skill missing: bead-lifecycle; run `ddx update --force` from the project root")
316	}
317	
318	func isUnknownHarnessError(err error) bool {
319		if err == nil {
320			return false
321		}
322		s := strings.ToLower(err.Error())
323		return strings.Contains(s, "unknown harness") || strings.Contains(s, "harness not found")
324	}
325	
326	func isMissingSkillError(err error) bool {
327		if err == nil {
328			return false
329		}
330		s := strings.ToLower(err.Error())
331		return strings.Contains(s, "skill missing") || strings.Contains(s, "bead-lifecycle")
332	}
