37	func (fileSessionLogExcerptReader) ReadSessionLogExcerpt(ctx context.Context, projectRoot, sessionID string, maxBytes int) (string, error) {
38		if ctx != nil {
39			if err := ctx.Err(); err != nil {
40				return "", err
41			}
42		}
43		path, ok := resolveSessionLogPath(projectRoot, sessionID)
44		if !ok {
45			return "", os.ErrNotExist
46		}
47		return readBoundedFileTail(path, maxBytes)
