141	func buildPostAttemptTriagePrompt(ctx context.Context, projectRoot string, b *bead.Bead, report ExecuteBeadReport, reader SessionLogExcerptReader, eventLister interface {
142		Events(id string) ([]bead.BeadEvent, error)
143	}) (string, error) {
144		env := triagePromptEnvelope{
145			Bead: triagePromptBead{
146				ID:           b.ID,
147				Title:        strings.TrimSpace(b.Title),
148				Status:       strings.TrimSpace(b.Status),
149				Priority:     b.Priority,
150				IssueType:    strings.TrimSpace(b.IssueType),
151				Labels:       append([]string(nil), b.Labels...),
152				Parent:       strings.TrimSpace(b.Parent),
153				Description:  strings.TrimSpace(b.Description),
154				Acceptance:   strings.TrimSpace(b.Acceptance),
155				Notes:        strings.TrimSpace(b.Notes),
156				Dependencies: append([]bead.Dependency(nil), b.Dependencies...),
157			},
158			ExecuteBead: report,
159			ProjectRoot: projectRoot,
160		}
161		if len(b.Extra) > 0 {
162			env.Bead.Extra = make(map[string]any, len(b.Extra))
163			for k, v := range b.Extra {
164				if k == "events" || k == "events_attachment" {
165					continue
166				}
167				env.Bead.Extra[k] = v
168			}
169		}
170	
171		if eventLister != nil {
172			events, err := eventLister.Events(b.ID)
173			if err == nil && len(events) > 0 {
174				start := len(events) - maxTriageEventCount
175				if start < 0 {
176					start = 0
177				}
178				env.RecentEvents = make([]bead.BeadEvent, 0, len(events)-start)
179				for _, ev := range events[start:] {
180					env.RecentEvents = append(env.RecentEvents, clampTriageEvent(ev))
181				}
182			}
183		}
184	
185		if report.SessionID != "" && reader != nil {
186			excerpt, err := reader.ReadSessionLogExcerpt(ctx, projectRoot, report.SessionID, defaultSessionLogExcerptBytes)
187			if err == nil && strings.TrimSpace(excerpt) != "" {
188				env.SessionExcerpt = excerpt
189				if path, ok := resolveSessionLogPath(projectRoot, report.SessionID); ok {
190					env.SessionLogPath = path
191				}
192			}
193		}
194	
195		body, err := json.MarshalIndent(env, "", "  ")
196		if err != nil {
197			return "", err
198		}
199	
200		var sb strings.Builder
201		sb.WriteString("MODE: triage\n")
202		sb.WriteString("You are the bead-lifecycle skill (" + postAttemptTriageSkillName + "). Classify the outcome of the attempt and return exactly one JSON object.\n")
203		sb.WriteString("Return structured JSON with the fields classification, recommended_action, rationale, suggested_amendments, suggested_followup_beads.\n")
204		sb.WriteString("Required output shape example: {\"classification\":\"transport\",\"recommended_action\":\"release_claim_retry\",\"rationale\":\"transient provider failure\",\"suggested_amendments\":[],\"suggested_followup_beads\":[]}\n")
205		sb.WriteString("Array fields must be arrays; use [] when none are needed.\n")
206		sb.WriteString("Use only the documented classifications and recommended_action values from the skill contract.\n")
207		sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
208		sb.WriteString("```json\n")
209		sb.Write(body)
210		sb.WriteString("\n```\n")
211		return sb.String(), nil
212	}
