214	func triageResultOutput(result *Result) (string, error) {
215		if result == nil {
216			return "", fmt.Errorf("triage hook: empty runner result")
217		}
218		text := strings.TrimSpace(result.CondensedOutput)
219		if text == "" {
220			text = strings.TrimSpace(result.Output)
221		}
222		if text == "" {
223			return "", fmt.Errorf("triage hook: empty output")
224		}
225		return text, nil
226	}
