228	func recordPostAttemptTriageEvent(store BeadEventAppender, beadID string, report ExecuteBeadReport, triage TriageResult, actor string, createdAt time.Time) {
229		if store == nil || beadID == "" {
230			return
231		}
232		triage = normalizeTriageResult(triage)
233		hasClassification := triage.Classification != ""
234		hasWarnings := len(triage.DecodeWarnings) > 0 || triage.Malformed
235		if !hasClassification && !hasWarnings {
236			return
237		}
238		amendments := triage.SuggestedAmendments
239		if amendments == nil {
240			amendments = []TriageAmendment{}
241		}
242		followups := triage.SuggestedFollowupBeads
243		if followups == nil {
244			followups = []FollowupBead{}
245		}
246		body := map[string]any{
247			"classification":           triage.Classification,
248			"recommended_action":       triage.RecommendedAction,
249			"rationale":                triage.Rationale,
250			"suggested_amendments":     amendments,
251			"suggested_followup_beads": followups,
252			"status":                   report.Status,
253			"detail":                   report.Detail,
254			"base_rev":                 report.BaseRev,
255			"result_rev":               report.ResultRev,
256			"session_id":               report.SessionID,
257		}
258		if len(triage.DecodeWarnings) > 0 {
259			body["decode_warnings"] = triage.DecodeWarnings
260		}
261		if triage.Malformed {
