527	func truncateBytes(s string, limit int) string {
528		if limit <= 0 || len(s) <= limit {
529			return s
530		}
531		const markerFmt = "\n…[truncated, %d bytes]\n"
532		marker := fmt.Sprintf(markerFmt, len(s))
533		if len(marker) >= limit {
534			return s[:limit]
535		}
536		head := (limit - len(marker)) / 2
537		tail := limit - len(marker) - head
538		return s[:head] + marker + s[len(s)-tail:]
539	}
