571	func readBoundedFileTail(path string, limitBytes int) (string, error) {
572		if limitBytes <= 0 {
573			return "", nil
574		}
575		f, err := os.Open(path)
576		if err != nil {
577			return "", err
578		}
579		defer f.Close()
580	
581		info, err := f.Stat()
582		if err != nil {
583			return "", err
584		}
585		size := info.Size()
586		if size <= 0 {
587			return "", nil
588		}
589		seek := int64(0)
590		if size > int64(limitBytes) {
591			seek = size - int64(limitBytes)
592		}
593		if _, err := f.Seek(seek, io.SeekStart); err != nil {
594			return "", err
595		}
596		data, err := io.ReadAll(f)
597		if err != nil {
598			return "", err
599		}
600		if seek > 0 {
601			return fmt.Sprintf("…[tail clipped to %d bytes]\n%s", limitBytes, string(data)), nil
602		}
603		return string(bytes.TrimSpace(data)), nil
604	}
